//! Tool definitions and dispatch for the MindLeak MCP server.

mod consolidation;
mod embeddings;
mod graph;
mod ingestion;
mod lifecycle;
mod telemetry;

use mindleak_core::MindLeak;
use mindleak_session::SessionRegistry;
use serde_json::{json, Value};

/// The advertised tool list (`tools/list`).
pub fn list() -> Vec<Value> {
    let mut definitions = vec![session_definition()];
    definitions.extend(graph::definitions());
    definitions.extend(ingestion::definitions());
    definitions.extend(lifecycle::graph_definitions());
    definitions.extend(consolidation::definitions());
    definitions.extend(lifecycle::context_definitions());
    definitions.extend(embeddings::definitions());
    definitions.extend(telemetry::definitions());
    definitions
        .into_iter()
        .map(apply_session_contract)
        .collect()
}

pub fn bind_session(params: &Value, sessions: &SessionRegistry) -> Result<Value, String> {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let mut bound = params.clone();
    let args = bound
        .get_mut("arguments")
        .and_then(Value::as_object_mut)
        .ok_or_else(|| "tool arguments must be an object".to_string())?;
    if name == "open_session" {
        let token = args
            .get("session_id")
            .and_then(Value::as_str)
            .ok_or_else(|| "missing required argument: session_id".to_string())?;
        let identity = sessions.open_session(token)?;
        args.insert("resolved_agent".to_string(), json!(identity.agent_id));
        return Ok(bound);
    }
    if requires_session(name) {
        let token = args
            .get("session_id")
            .and_then(Value::as_str)
            .ok_or_else(|| "missing required argument: session_id".to_string())?;
        let identity = sessions.resolve(token)?;
        args.insert("agent".to_string(), json!(identity.agent_id));
        args.insert("agent_id".to_string(), json!(identity.agent_id));
        args.insert("exclude_agent".to_string(), json!(identity.agent_id));
    }
    Ok(bound)
}

/// Dispatch a `tools/call` request with observability: every call is timed,
/// traced (stderr-only), and recorded to the durable telemetry audit trail so an
/// operator can confirm what ran and whether it succeeded (ADR-0010).
pub fn call(engine: &MindLeak, params: &Value) -> Result<Value, String> {
    let name = params
        .get("name")
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let span = tracing::info_span!("tool_call", tool = %name);
    let _enter = span.enter();
    let start = std::time::Instant::now();
    let result = dispatch(engine, params);
    let duration_ms = start.elapsed().as_millis() as i64;
    let detail = result.as_ref().err().map(|e| json!({ "error": e }));
    engine.record_tool_call(&name, result.is_ok(), duration_ms, detail);
    match &result {
        Ok(_) => tracing::info!(tool = %name, duration_ms, "ok"),
        Err(e) => tracing::warn!(tool = %name, duration_ms, error = %e, "tool error"),
    }
    result
}

/// Route a `tools/call` request to the matching tool implementation.
fn dispatch(engine: &MindLeak, params: &Value) -> Result<Value, String> {
    let name = params
        .get("name")
        .and_then(Value::as_str)
        .ok_or("missing tool name")?;
    let args = params.get("arguments").cloned().unwrap_or(Value::Null);

    if name == "open_session" {
        return Ok(text_result(&json!({
            "agent_id": req_str(&args, "resolved_agent")?,
        })));
    }

    if let Some(result) = graph::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = ingestion::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = lifecycle::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = consolidation::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = embeddings::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = telemetry::dispatch(engine, name, &args) {
        return result;
    }

    Err(format!("unknown tool: {name}"))
}

fn session_definition() -> Value {
    json!({
        "name": "open_session",
        "description": "Register one client-minted 128-bit session id and return its stable cross-plane agent identity. Reuse the same session_id on every identity-bearing tool call and after server restarts.",
        "inputSchema": {
            "type": "object",
            "properties": {
                "session_id": { "type": "string", "pattern": "^[0-9a-f]{32}$" }
            },
            "required": ["session_id"]
        }
    })
}

fn requires_session(name: &str) -> bool {
    matches!(
        name,
        "record_architectural_decision"
            | "ingest_execution"
            | "ingest_commit"
            | "ingest_file"
            | "boost_entity"
            | "working_set"
            | "evidence_for"
            | "check_overlap"
    )
}

fn apply_session_contract(mut tool: Value) -> Value {
    let name = tool.get("name").and_then(Value::as_str).unwrap_or("");
    if !requires_session(name) {
        return tool;
    }
    if let Some(properties) = tool
        .get_mut("inputSchema")
        .and_then(|schema| schema.get_mut("properties"))
        .and_then(Value::as_object_mut)
    {
        for legacy in ["agent", "agent_id", "exclude_agent"] {
            properties.remove(legacy);
        }
        properties.insert(
            "session_id".to_string(),
            json!({
                "type": "string",
                "pattern": "^[0-9a-f]{32}$",
                "description": "Session id previously registered with open_session."
            }),
        );
    }
    if let Some(required) = tool
        .get_mut("inputSchema")
        .and_then(|schema| schema.get_mut("required"))
        .and_then(Value::as_array_mut)
    {
        required.retain(|value| value != "agent" && value != "agent_id");
        if !required.iter().any(|value| value == "session_id") {
            required.push(json!("session_id"));
        }
    } else if let Some(schema) = tool.get_mut("inputSchema").and_then(Value::as_object_mut) {
        schema.insert("required".to_string(), json!(["session_id"]));
    }
    tool
}

fn text_result(value: &Value) -> Value {
    let text = serde_json::to_string_pretty(value).unwrap_or_else(|_| value.to_string());
    json!({ "content": [{ "type": "text", "text": text }] })
}

/// A tool result that renders as Markdown in chat while keeping the structured
/// JSON in `structuredContent` for programmatic consumers (the extension client
/// and agents). VS Code renders `content`; machine consumers read
/// `structuredContent`, so the display can be rich without breaking parsers.
fn rendered_result(markdown: impl Into<String>, value: &Value) -> Value {
    json!({
        "content": [{ "type": "text", "text": markdown.into() }],
        "structuredContent": value,
    })
}

fn req_str(args: &Value, key: &str) -> Result<String, String> {
    args.get(key)
        .and_then(Value::as_str)
        .map(str::to_string)
        .ok_or_else(|| format!("missing required argument: {key}"))
}

fn opt_str(args: &Value, key: &str) -> Option<String> {
    args.get(key).and_then(Value::as_str).map(str::to_string)
}

fn opt_i64(args: &Value, key: &str, default: i64) -> i64 {
    args.get(key).and_then(Value::as_i64).unwrap_or(default)
}

fn required_i64(args: &Value, key: &str) -> Result<i64, String> {
    args.get(key)
        .and_then(Value::as_i64)
        .ok_or_else(|| format!("missing required integer argument: {key}"))
}

fn opt_f64(args: &Value, key: &str, default: f64) -> f64 {
    args.get(key).and_then(Value::as_f64).unwrap_or(default)
}

fn str_array(args: &Value, key: &str) -> Vec<String> {
    args.get(key)
        .and_then(Value::as_array)
        .map(|a| {
            a.iter()
                .filter_map(Value::as_str)
                .map(str::to_string)
                .collect()
        })
        .unwrap_or_default()
}

#[cfg(test)]
mod tests {
    use super::*;
    use mindleak_core::MindLeak;

    pub(super) fn call_ok(engine: &MindLeak, name: &str, args: Value) -> Value {
        let mut args = args;
        if requires_session(name) {
            let object = args
                .as_object_mut()
                .expect("test arguments must be an object");
            object
                .entry("agent")
                .or_insert_with(|| json!("session:v1:test:fixed"));
            object
                .entry("agent_id")
                .or_insert_with(|| json!("session:v1:test:fixed"));
            object
                .entry("exclude_agent")
                .or_insert_with(|| json!("session:v1:test:fixed"));
        }
        let params = json!({ "name": name, "arguments": args });
        call(engine, &params).expect("tool call should succeed")
    }

    pub(super) fn content_text(result: &Value) -> String {
        result["content"][0]["text"].as_str().unwrap().to_string()
    }

    #[test]
    fn list_advertises_all_tools() {
        let names: Vec<String> = list()
            .iter()
            .map(|t| t["name"].as_str().unwrap().to_string())
            .collect();
        for expected in [
            "graph_multi_hop_query",
            "get_impact_radius",
            "record_architectural_decision",
            "recall",
            "index",
            "telemetry_snapshot",
            "consolidate_signal",
            "promotion_candidates",
            "working_set",
            "export_graph",
            "backup_database",
            "reset_database",
        ] {
            assert!(
                names.contains(&expected.to_string()),
                "missing tool: {expected}"
            );
        }
        // Tool names are unique; new tools extend the surface rather than
        // colliding on a hand-maintained count.
        let unique: std::collections::HashSet<&String> = names.iter().collect();
        assert_eq!(unique.len(), names.len(), "duplicate tool name");
        let evidence = list()
            .into_iter()
            .find(|tool| tool["name"] == "evidence_for")
            .unwrap();
        assert!(evidence["inputSchema"]["properties"]["session_id"].is_object());
        assert!(evidence["inputSchema"]["properties"]["agent_id"].is_null());
    }

    #[test]
    fn ingest_file_then_query_dispatches() {
        let engine = MindLeak::open_in_memory().unwrap();
        call_ok(
            &engine,
            "ingest_file",
            json!({ "path": "src/auth.ts", "content": "export function validateSession() {}" }),
        );
        let res = call_ok(
            &engine,
            "graph_multi_hop_query",
            json!({ "seed_entity": "src/auth.ts", "max_depth": 2, "min_weight": 0.05 }),
        );
        assert!(content_text(&res).contains("validateSession"));
    }

    #[test]
    fn unknown_tool_is_error() {
        let engine = MindLeak::open_in_memory().unwrap();
        let params = json!({ "name": "nope", "arguments": {} });
        assert!(call(&engine, &params).unwrap_err().contains("unknown tool"));
    }
}
